import fs from"fs-promise";import Promise from"bluebird";import path from"path";import{getEnv}from"./manager";import startShell from"./startShell";import{biomeFolderName}from"./constants";export default function add(r,o){return getEnv(r).then(([r,t])=>{o.forEach(([o,e])=>{o=o.trim(),r[o]=e,console.log(`Exported ${o}="${e}" inside ${t}...`)});let e=path.join(biomeFolderName(),`${t}.json`);return fs.writeFile(e,JSON.stringify(r,null,2))})}